mapper.select:
select d.device_id, d.meter_id, d.imei, d.meter_no, d.inbound_time, ml.forward_total_flow, ml.reverse_total_flow, d.prep_id, sp.prep_no, ml.main_ip, ml.backup_ip, tm.meter_name, tm.meter_model, tm.meter_caliber, d.protocol_type, case d.protocol_type when 0 then 'CJT188' when 1 then 'SR' when 2 then '恩乐曼' else '' end as protocol_type_name, d.carrier, case d.carrier when 0 then '移动' when 1 then '电信' when 2 then '联通' else '' end as carrier_name, ml.valve_status, ml.battery_voltage, d.box_no, d.vendor_code, ml.iccid, ml.csq, ml.rsrp, ml.rsrq, d.stock_status, d.test_status, d.outbound_time, d.outbound_operator_name, d.remark, d.update_time from tb_device d left join tb_meter_latest ml on ml.device_id = d.device_id left join tb_meter tm on tm.id = d.meter_id left join tl_stock_prep sp on sp.id = d.prep_id where d.is_deleted = 0
and ( d.imei like concat('%', #{keyword}, '%') or d.meter_no like concat('%', #{keyword}, '%') or sp.prep_no like concat('%', #{keyword}, '%') )
and d.stock_status = #{stockStatus}
and d.test_status = #{testStatus}
order by d.inbound_time desc
